dock.active:

my active = call get_material_wood(Feature('Tischmaterial')) or call table_kelco();
if (active) {
	my tisch_500 = ParentOfType(part, 'mainstructure', 'tischeinheit_125x50_74');
	if (tisch_500) {
		my winkel_list = ChildrenListOfType(tisch_500, 'eckwinkel_90');
		my ok = true;
		for (my w: winkel_list) {
			ok =  ConnectedDockCount(w, 'winkel2gelenk') eq 0;
			if (not ok) {
				active = false;
				break;
			}
		}
	};

	active;
};
return active;

my tisch_500 = ParentOfType(part, 'mainstructure', 'tischeinheit_125x50_74');
if (tisch_500) {
	my tischblatt = ChildOfType(tisch_500, 'tisch_50_std');
	if (tischblatt) {
		return ConnectedDockCount(tischblatt, 'tisch2rosti') eq 0;
	};
};

return true;

